import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowRight, Star, Globe, Share2, BarChart2 } from 'lucide-react';

const AMBER = '#F5A623';
const NAVY  = '#0A1628';

const Beranda = () => {
  const navigate = useNavigate();
  const [tracking, setTracking] = useState('');

  const handleTrack = () => {
    if (tracking.trim()) navigate(`/pesanan?resi=${tracking}`);
  };

  const services = [
    {
      svg: (
        <svg viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2"
          strokeLinecap="round" strokeLinejoin="round" style={{width:24,height:24}}>
          <rect x="2" y="7" width="20" height="13" rx="2"/>
          <path d="M16 7V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v2"/>
          <line x1="12" y1="12" x2="12" y2="16"/>
          <line x1="10" y1="14" x2="14" y2="14"/>
        </svg>
      ),
      title: 'Angkutan Berat',
      desc: 'Transportasi kargo skala besar dengan armada heavy-duty yang dirawat rutin untuk performa maksimal.',
    },
    {
      svg: (
        <svg viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2"
          strokeLinecap="round" strokeLinejoin="round" style={{width:24,height:24}}>
          <rect x="1" y="3" width="15" height="13" rx="1"/>
          <path d="M16 8h4l3 3v5h-7V8z"/>
          <circle cx="5.5" cy="18.5" r="2.5"/>
          <circle cx="18.5" cy="18.5" r="2.5"/>
        </svg>
